#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-26

# Test: every migration .sql ships INTO the bundle dir (dist/).
#
# Why this exists (#2012 regression guard):
#   The SQLite migration runner reads NNN-*.sql from its own directory
#   (dirname(import.meta.url)) at runtime. In the distributed plugin that dir is
#   dist/, and build-plugins.sh rsyncs dist/ into the plugin — but rsync
#   EXCLUDES src/, where the source .sql live (src/hooks/src/lib/sqlite-migrations).
#   Unless the build copies them into dist/, runMigrations() finds zero files and
#   NO tables are created in the installed plugin — silently, because every
#   registry write is guarded. esbuild.config.mjs copyMigrations() performs that
#   copy; this test guards it. (Tests passed but prod was broken before #2012:
#   vitest runs the source tree, where .sql sit next to index.ts.)
#
# Exit: 0 = every src migration is shipped into dist/, 1 = one is missing/stale.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
SRC="$REPO_ROOT/src/hooks/src/lib/sqlite-migrations"
DIST="$REPO_ROOT/src/hooks/dist"

if [[ ! -d "$DIST" ]]; then
  echo "ERROR: $DIST not found — run the hooks build first" >&2
  exit 1
fi

echo "=== Migration ship guard (#2012) ==="

FAILED=0
CHECKED=0

shopt -s nullglob
for src_sql in "$SRC"/[0-9][0-9][0-9]-*.sql; do
  CHECKED=$((CHECKED + 1))
  base=$(basename "$src_sql")
  dist_sql="$DIST/$base"
  if [[ ! -f "$dist_sql" ]]; then
    echo "FAIL: $base is NOT shipped into dist/ — migration will not run in the plugin"
    FAILED=1
    continue
  fi
  if ! cmp -s "$src_sql" "$dist_sql"; then
    echo "FAIL: $base in dist/ differs from source — stale copy, rebuild hooks"
    FAILED=1
  fi
done

echo ""
echo "Migrations checked: $CHECKED"
if [[ "$CHECKED" -eq 0 ]]; then
  echo "FAIL: no migration .sql found in $SRC (expected at least 001-initial.sql)"
  exit 1
fi
if [[ "$FAILED" -ne 0 ]]; then
  echo "FAIL: migration(s) missing from dist/ — see copyMigrations() in src/hooks/esbuild.config.mjs"
  exit 1
fi
echo "PASS: all $CHECKED migration .sql ship into dist/"
exit 0
